rules:
{
  "任务描述": "根据文档，生成符合企业管理要求的、结构化、深度量化的会议纪要。",
  "输出格式": "JSON",
  "输出结构": {
    "会议基本信息": {
      "会议名称": "提取完整主题",
      "会议时间": "提取具体起止时间（如：2026-03-18 16:00-18:00），注意时长准确性",
      "会议地点": "提取地点或标注‘Welink线上会议’",
      "参会人员": "列出所有发言人姓名",
      "纪要整理": "从原文提取或默认指定",
      "纪要审核人": "留空"
    },
    "会议核心议题": [
      {
        "议题名称": "提炼该段落的核心议题",
        "内容摘要": "总结会议讨论内容，必须包含：决策结论、量化目标（含具体数值/百分比）、执行措施。",
        "关键定义": "如果原文中对某个概念有明确定义（如‘标准定义：...’），必须原样提取并注明。"
      }
    ],
    "遗留事项": [
      {
        "事项描述": "具体行动项（不使用模糊动词，需写出具体交付物）",
        "责任人": "明确具体姓名，多人用顿号分隔",
        "完成时间": "明确具体日期，若原文未提及需标注‘时间待定’"
      }
    ]
  },
  "撰写规范（重要）": [
    "1. 【量化与细节】：必须保留原文中的关键数据。例如，不要只写‘制定了目标’，要写‘制定目标：至少落地1个，挑战目标2个’。",
    "2. 【标准定义】：当原文提到某项工作的具体标准或定义时，需在‘内容摘要’或‘关键定义’中详细列出。例如：‘头腰部客户续框资格保障率100%（标准定义：无SLA考核、安全与风控问题导致的无法参与续框...）’。",
    "3. 【遗留事项粒度】：遗留事项需拆解到最小可执行单元。如果是一个大项目，需拆解为具体的子任务（如：初稿汇总、方案设计、流程刷新等）。",
    "4. 【结构化展示】：在描述重点工作拆解时，使用层级结构（如①②③）列出具体目标及其对应的详细定义。",
    "5. 【专业术语】：准确保留业务术语（如SLA、PBC、ACH模型、本体构建等），不得简化或误读。"
  ],
  "负面清单（需避免的情况）": [
    "1. 遗漏具体的量化指标数值。",
    "2. 将多个不同责任人的任务合并为一条遗留事项。",
    "3. 仅做浅层概括，丢失‘标准定义’或‘具体措施’等关键业务信息。"
  ]
}
